function revealOnScroll(){const e=document.querySelectorAll(".hero-section, .storytelling-section, .lead-magnet-section, .authority-block, .cta-final-block, .metodo-borgia-section, .case-story-block, .section-fade"),t=e=>{e.isIntersecting&&e.target.classList.add("visible")},o=new IntersectionObserver(e=>{e.forEach(t)},{threshold:.18});e.forEach(e=>{e.classList.add("section-fade"),o.observe(e)})}document.addEventListener("DOMContentLoaded",revealOnScroll);